/**
 * MedX taborder accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Logical tab order for complex forms.
 */
const TABORDER_TOKENS = Object.freeze({
  primary: { value: "a11y-taborder-primary", scope: "a11y" },
  secondary: { value: "a11y-taborder-secondary", scope: "a11y" },
  muted: { value: "a11y-taborder-muted", scope: "a11y" },
  accent: { value: "a11y-taborder-accent", scope: "a11y" },
  surface: { value: "a11y-taborder-surface", scope: "a11y" },
});

const TABORDER_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const TABORDER_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const taborderRegistry = new Map();
const TABORDER_listeners = new Set();
let TABORDER_seq = 0;

function createTaborderId(prefix = "medx-a11y-taborder") {
  TABORDER_seq += 1;
  return `${prefix}-${TABORDER_seq}`;
}

function registerTaborder(config = {}) {
  const entryId = config.id ?? createTaborderId();
  const preset = TABORDER_PRESETS[config.preset ?? "default"] ?? TABORDER_PRESETS.default;
  const token = TABORDER_TOKENS[config.token ?? preset.token] ?? TABORDER_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: TABORDER_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  taborderRegistry.set(entryId, entry);
  notifyTaborderListeners("register", entry);
  return entry;
}

function updateTaborder(id, patch = {}) {
  const entry = taborderRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyTaborderListeners("update", entry);
  return entry;
}

function resolveTaborder(id) {
  const entry = taborderRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listTaborderEntries(filter = {}) {
  let items = Array.from(taborderRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onTaborderEvent(listener) {
  TABORDER_listeners.add(listener);
  return () => TABORDER_listeners.delete(listener);
}

function notifyTaborderListeners(type, entry) {
  for (const listener of TABORDER_listeners) {
    try {
      listener({ type, entry, registrySize: taborderRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:taborder] listener error", err.message);
    }
  }
}

function getTaborderMetrics() {
  const items = listTaborderEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(TABORDER_TOKENS).length,
    presets: Object.keys(TABORDER_PRESETS).length,
  };
}

async function runMedxTaborder() {
  console.log("[medx:ui:a11y:taborder] runtime initialized");
  console.log(`[medx:ui:a11y:taborder] tokens=${Object.keys(TABORDER_TOKENS).length} presets=${Object.keys(TABORDER_PRESETS).length}`);

  const events = [];
  onTaborderEvent((e) => events.push(e.type));

  const domains = Object.keys(TABORDER_SUPPLY_CHAIN);
  const presets = Object.keys(TABORDER_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerTaborder({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/taborder" },
    });
  }

  const first = listTaborderEntries()[0];
  if (first) updateTaborder(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getTaborderMetrics();
  const resolved = first ? resolveTaborder(first.id) : null;

  console.log(`[medx:ui:a11y:taborder] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:taborder] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:taborder] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:taborder] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:taborder] bootstrap complete");
}

module.exports = runMedxTaborder;
